// App.jsx (React)
import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [jobs, setJobs] = useState([]);

  useEffect(() => {
    // बॅकएंडवरून जॉब्स आणणे
    axios.get('http://localhost:5000/api/jobs')
      .then(res => setJobs(res.data))
      .catch(err => console.error(err));
  }, []);

  return (
    <div className="flex min-h-screen bg-gray-100">
      {/* Sidebar */}
      <div className="w-64 bg-slate-900 text-white p-6 shadow-xl">
        <h2 className="text-2xl font-bold text-blue-400 mb-10">FreelanceHub</h2>
        <nav className="space-y-4">
          <a href="#" className="block p-3 bg-blue-600 rounded">Dashboard</a>
          <a href="#" className="block p-3 hover:bg-slate-700 transition">Find Jobs</a>
          <a href="#" className="block p-3 hover:bg-slate-700 transition">My Bids</a>
        </nav>
      </div>

      {/* Main Content */}
      <div className="flex-1 p-10">
        <header className="flex justify-between items-center mb-10">
          <h1 className="text-3xl font-bold text-gray-800">Available Projects</h1>
          <button className="bg-green-500 text-white px-6 py-2 rounded-full font-semibold shadow-lg">Post a Job</button>
        </header>

        {/* Job Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          {jobs.map(job => (
            <div key={job._id} className="bg-white p-6 rounded-xl shadow-md border-t-4 border-blue-500">
              <h3 className="text-xl font-bold text-gray-800">{job.title}</h3>
              <p className="text-blue-600 font-semibold mt-2">{job.budget}</p>
              <p className="text-gray-600 mt-3 line-clamp-2">{job.description}</p>
              <div className="mt-4 flex gap-2">
                {job.skills.map(skill => (
                  <span className="bg-gray-200 px-3 py-1 rounded-full text-xs">{skill}</span>
                ))}
              </div>
              <button className="w-full mt-6 bg-slate-800 text-white py-2 rounded-lg hover:bg-black">Bid Now</button>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default App;
